import boto3

br = boto3.client('bedrock-runtime')

# ツール定義
tools = [{
    "toolSpec": {
        "name": "get_weather",
        "description": "指定した都市の現在の天気を取得する",
        "inputSchema": {
            "json": {
                "type": "object",
                "properties": {
                    "city": {"type": "string",
                             "description": "都市名"}
                },
                "required": ["city"]
            }
        }
    }
}]

response = br.converse(
    modelId='anthropic.claude-3-5-sonnet-20241022-v2:0',
    messages=[{'role': 'user',
               'content': [{'text': '東京の天気は?'}]}],
    toolConfig={'tools': tools, 'toolChoice': {'auto': {}}}
)
# stopReason == 'tool_use' の場合にツール実行
